# CORRECT: isolated adapter, config-driven model, stop_reason check
class AnthropicAdapter:
    def __init__(self) -> None:
        self._client = anthropic.Anthropic(
            api_key=os.environ["ANTHROPIC_API_KEY"],
            timeout=httpx.Timeout(connect=5.0, read=60.0, write=5.0, pool=5.0),
            max_retries=0,   # retry logic is handled by the caller with jitter
        )
        self._model = os.environ.get("LLM_MODEL", "claude-haiku-4-5-20251001")

    def chat(self, messages: list[dict], max_tokens: int = 512) -> str:
        resp = self._client.messages.create(
            model=self._model,
            max_tokens=max_tokens,
            messages=messages,
        )
        if resp.stop_reason == "max_tokens":
            raise OutputTruncatedError(f"Response truncated at {max_tokens} tokens")
        return resp.content[0].text

