import json

def extract_entities(llm_response: str) -> list[str]:
    try:
        parsed = json.loads(llm_response)
    except json.JSONDecodeError as exc:
        raise LLMOutputParseError(f"Model did not return valid JSON: {exc}") from exc
    if not isinstance(parsed, list):
        raise LLMOutputParseError(f"Expected list, got {type(parsed).__name__}")
    # Sanitise each entity before returning
    return [str(entity)[:200] for entity in parsed]

