# scripts/check_hardcoded_model.py — catch hardcoded model names in code changes
# Run in CI on every PR touching Python files
import ast, sys
from pathlib import Path

KNOWN_MODELS = {
    "claude-3-opus-20240229", "claude-3-sonnet-20240229", "claude-3-haiku-20240307",
    "gpt-4o", "gpt-4-turbo", "gpt-3.5-turbo",
    "gemini-1.5-pro", "gemini-1.5-flash",
}

class ModelStringVisitor(ast.NodeVisitor):
    def __init__(self, path: str) -> None:
        self.path = path
        self.violations: list[tuple[int, str]] = []

    def visit_Constant(self, node: ast.Constant) -> None:
        if isinstance(node.value, str) and node.value in KNOWN_MODELS:
            self.violations.append((node.lineno, node.value))

failed = False
for path in Path("src").rglob("*.py"):
    tree = ast.parse(path.read_text())
    visitor = ModelStringVisitor(str(path))
    visitor.visit(tree)
    for lineno, model in visitor.violations:
        print(f"FAIL {path}:{lineno} — hardcoded model name '{model}' (use config/env var)")
        failed = True

sys.exit(1 if failed else 0)
